class Solution {
    private static final int MOD = 1_000_000_007;

    public int possibleStringCount(String word, int k) {
        int n = word.length();
        if (k > n) return 0;
        if (k == n) return 1;

        // Precompute factorials and inverse factorials up to n
        long[] fact = new long[n + 1];
        long[] invFact = new long[n + 1];
        fact[0] = 1;
        for (int i = 1; i <= n; i++) {
            fact[i] = fact[i - 1] * i % MOD;
        }
        invFact[n] = pow(fact[n], MOD - 2);
        for (int i = n - 1; i >= 0; i--) {
            invFact[i] = invFact[i + 1] * (i + 1) % MOD;
        }

        // DP[i][j] = number of subsequences of length j using first i characters
        long[][] dp = new long[n + 1][k];
        dp[0][0] = 1;
        int[] last = new int[26];
        for (int i = 1; i <= n; i++) {
            int c = word.charAt(i - 1) - 'a';
            for (int j = 0; j < k; j++) {
                dp[i][j] = dp[i - 1][j];
                if (j > 0) {
                    dp[i][j] = (dp[i][j] + dp[i - 1][j - 1]) % MOD;
                }
                if (last[c] > 0 && j >= (i - last[c])) {
                    dp[i][j] = (dp[i][j] - dp[last[c] - 1][j - (i - last[c])] + MOD) % MOD;
                }
            }
            last[c] = i;
        }

        long res = 0;
        for (int j = 0; j < k; j++) {
            res = (res + dp[n][j]) % MOD;
        }
        return (int) res;
    }

    private long pow(long a, long b) {
        long res = 1;
        while (b > 0) {
            if ((b & 1) == 1) res = res * a % MOD;
            a = a * a % MOD;
            b >>= 1;
        }
        return res;
    }
}
